import {Map} from 'immutable'

export function arrToMap(arr, ItemRedcord) {
    return arr.reduce(
        /*(acc, item) => ({
            ...acc,
            [item.id]: item
        }),*/

        (acc, item) => acc.set(item.id, ItemRedcord ? new ItemRedcord(item) : item),
        new Map()
    )
}
